CODE_EXAMPLE:
// Before
class Employee {
  String quota; // only used by Salesman
}

// After
class Employee {}

class Salesman extends Employee {
  String quota;
}

UNIT_TEST_EXAMPLE:
@Test
public void testPushDownField() {
  Salesman salesman = new Salesman();
  salesman.setQuota("1000");
  assertEquals("1000", salesman.getQuota());
}
